create table pis_storitve_pos.zahteva (
    id                          number(19, 0) not null enable,
    tip_zahteve                 varchar2(100 char),
    naslovnik                   varchar2(100 char),
    public_id                   varchar2(36 char) not null enable,
    mnenje_id                   number(19, 0) not null enable,
    aplikacija                  varchar2(10 char) not null enable,
    organizacija_id             varchar2(100 char),
    institucija                 varchar2(255 char),
    maticna_stevilka            varchar2(20 char),
    data                        clob,
    struktura_gradiva_id        number(19, 0),
    zip_id                      varchar2(128 char),
    status                      varchar2(40 char) not null enable,
    datum_cre                   timestamp(6) not null enable,
    datum_mod                   timestamp(6),
    callback_url                varchar2(255 char),
    version                     number(19, 0) default 0 not null enable,
    status_info                 varchar2(4000 char),
    tip_storitve                varchar2(255 char),
    pristojnost                 varchar2(255 char),
    vrsta_mnenja                varchar2(255 char),
    maticna_stevilka_recipienta varchar2(20 char),
    organizacija_koda           varchar2(255 char) not null enable
);

create unique index pis_storitve_pos.ak_zahteva__public_id on
    pis_storitve_pos.zahteva (
        public_id
    );

alter table pis_storitve_pos.zahteva
    add constraint pk_zahteva primary key ( id )
        using index enable;

alter table pis_storitve_pos.zahteva
    add unique ( public_id )
        using index pis_storitve_pos.ak_zahteva__public_id enable;


